        raise ValueError(f"Invalid JSON in request body: {e.msg}") from e

    if not isinstance(data, dict):
        raise ValueError("JSON body must be an object.")

    return data


def decode_json_request(request):
    """
    Validate the Content-Type and decode JSON from a request dict.

    Args:
        request (dict): A dictionary containing 'headers' (dict) and 'body' (str or bytes).

    Returns:
        dict: Parsed JSON object from the request body.

    Raises:
        ValueError: If the request is invalid, Content-Type is not application/json,
                    or JSON decoding/format issues occur.
    """
    if not isinstance(request, dict):
        raise ValueError("Request must be a dict with 'headers' and 'body'.")

    if 'headers' not in request:
        raise ValueError("Request missing 'headers' key.")

    headers = request['headers']
    if not isinstance(headers, dict):
        raise ValueError("Request 'headers' must be a dict.")

    if not validate_content_type(headers):
        raise ValueError("Invalid Content-Type. Expected 'application/json'.")

    return extract_json_body(request)

